const signupMethodEl=document.getElementById("signup-method"),paymentPackageEl=document.getElementById("payment-package"),paymentBtn=document.getElementById("payment-cta"),logoutBtn=document.getElementById("logout-btn");function scrambleText(t,e,n=5e3){const o="ABCDEFGHIJKLMNOPQRSTUVWXYZabcdefghijklmnopqrstuvwxyz0123456789!@#$%^&*()_+-=[]{}|;:,.<>?",l=20*e.length;let a=0;const s=setInterval(()=>{let n="";for(let t=0;t<e.length;t++)n+=t<a/20?e[t]:o.charAt(Math.floor(88*Math.random()));t.textContent=n,a++,a>l&&(clearInterval(s),t.textContent=e)},n/l)}window.addEventListener("load",()=>{paymentPackageEl.textContent=sessionStorage.getItem("paymentPackage")||"Basic (Configure Later)"}),paymentBtn.addEventListener("click",()=>{window.location.href="/Frontend/pay.html"}),logoutBtn.addEventListener("click",()=>{sessionStorage.clear(),alert("Logged out"),window.location.href="index.html"}),window.onload=()=>{const t=sessionStorage.getItem("userUID"),e=sessionStorage.getItem("userEmail"),n=document.getElementById("login-status");t&&e?(console.log("User is logged in:",e),n.textContent="Active",n.style.color="#00c853"):(console.log("User is not logged in."),n.textContent="Inactive",n.style.color="#d50000")},window.addEventListener("DOMContentLoaded",()=>{const t=document.getElementById("uid-label");t&&scrambleText(t,"User ID:",5e3)});const chars="ABCDEFGHIJKLMNOPQRSTUVWXYZabcdefghijklmnopqrstuvwxyz0123456789!@#$%^&*()-_=+[]{}<>?";function shuffleText(t,e,n=5e3,o=50){let l=n/o,a=0;const s=setInterval(()=>{let n="";for(let t=0;t<e.length;t++)n+=a/2>t?e[t]:chars.charAt(Math.floor(83*Math.random()));t.textContent=n,a++,a>=l&&(t.textContent=e,clearInterval(s))},o)}window.addEventListener("DOMContentLoaded",()=>{document.querySelectorAll(".shuffle-text").forEach(t=>{const e=t.textContent;t.textContent="",shuffleText(t,e,5e3,50)})});